import {{ Injectable }} from '@nestjs/common';
import {{ ApiService }} from './models/api.model';
import {{ ApiServiceRepository }} from './repositories/api.repository';

@Injectable()
export class ApiServiceService {{
  constructor(
    private readonly repository: ApiServiceRepository,
  ) {{}}

  async findAll(): Promise<ApiService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<ApiService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<ApiService>): Promise<ApiService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<ApiService>): Promise<ApiService> {{
    return this.repository.update(id, data);
  }}
}}

